"""Unit tests for the main application."""

import unittest
import sys
sys.path.append('..')

from main import calculate_total, process_order, validate_item
from exceptions import InvalidItemError

print("Executing test_main.py")

class TestMain(unittest.TestCase):
    """Test cases for the main application."""

    def test_calculate_total(self):
        """Test the calculate_total function."""
        items = [
            {'name': 'Item 1', 'price': 10.0},
            {'name': 'Item 2', 'price': 20.0}
        ]
        self.assertEqual(calculate_total(items), 30.0)

    def test_process_order(self):
        """Test the process_order function."""
        items = [
            {'name': 'Item 1', 'price': 10.0},
            {'name': 'Item 2', 'price': 20.0}
        ]
        result = process_order('ORD-001', items)
        self.assertEqual(result, {
            'order_id': 'ORD-001',
            'total': 30.0,
            'status': 'processed'
        })

    def test_validate_item_valid(self):
        """Test the validate_item function with a valid item."""
        item = {'name': 'Item 1', 'price': 10.0}
        self.assertTrue(validate_item(item))

    def test_validate_item_invalid(self):
        """Test the validate_item function with an invalid item."""
        item = {'name': 'Item 1'}
        with self.assertRaises(InvalidItemError):
            validate_item(item)

if __name__ == '__main__':
    print("Running tests from __main__")
    unittest.main()

import json

def validate_item(item):
    if "name" not in item:
        return False
    return True

def process_item(item):
    if not validate_item(item):
        return None
    return item

def main():
    item = {"name": "Item 1"}
    processed_item = process_item(item)
    print(json.dumps(processed_item))

if __name__ == "__main__":
    main()

